class Solution:
    def maxSumMinProduct(self, nums):
        MOD = 10**9 + 7
        n = len(nums)
        best = 0
        for i in range(n):
            mn = nums[i]
            total = 0
            for j in range(i, n):
                if nums[j] < mn:
                    mn = nums[j]
                total += nums[j]
                cand = mn * total
                if cand > best:
                    best = cand
        return best % MOD

